export default class Transition{constructor(){this.overlay=document.getElementById("page-transition"),this.progressBar=document.getElementById("progress-bar")}startProgress(){this.progressBar&&(this.progressBar.style.opacity="1",this.progressBar.style.width="30%")}setProgress(s){this.progressBar&&(this.progressBar.style.width=`${s}%`)}async finishProgress(){this.progressBar&&(this.progressBar.style.width="100%",await this.delay(300),this.progressBar.style.opacity="0",await this.delay(300),this.progressBar.style.width="0%")}async out(s){this.startProgress(),this.overlay&&(this.overlay.classList.add("is-active"),await this.delay(500))}async in(s){this.setProgress(80),this.overlay&&(this.overlay.classList.remove("is-active"),await this.delay(500)),await this.finishProgress()}delay(s){return new Promise(t=>setTimeout(t,s))}}